Query:
let Upn = '{UserPrincipalName}';
let TimeFrame = {TimeFrame};
Anomalies
| where Entities has Upn or UserPrincipalName =~ Upn | where TimeGenerated > ago(TimeFrame)

let Upn = '{UserPrincipalName}';
let TimeFrame = {TimeFrame};
let KnownApps = SigninLogs
| where UserPrincipalName =~ Upn
// Adjust the timerange depending on the retention period
| where TimeGenerated > ago(90d) and TimeGenerated < ago(TimeFrame)
| distinct AppId;
SigninLogs
| where UserPrincipalName =~ Upn
| where TimeGenerated > ago(TimeFrame)
| where not(AppId in~ (KnownApps))
// If the AppID is empty then it is a third party App.
| extend IsExternalApp = iff(isempty(AppId), 'True', 'False')
| project IsExternalApp, AppDisplayName, Identity, IPAddress, ClientAppUsed, UserPrincipalName

let Upn = '{UserPrincipalName}';
let TimeFrame = {TimeFrame};
// Define PersistenceEvents, list can be appended with other events or your choosing
let PersistenceEvents = dynamic(['add member', 'add device', 'register device', 'add service principal', 'update service principal', 'add user', 'enable account', 'add group', 'Invite external user', 'Add application', 'add app', 'User registered security info']);
AuditLogs
// Filter only on the RiskyUsers defined
| where TimeGenerated > ago(TimeFrame)
| where InitiatedBy has Upn
// Filter on DiscoveryEvents
| where OperationName has_any (PersistenceEvents)
| project TimeGenerated, Identity, OperationName, Category, ResultDescription, Result

let Upn = '{UserPrincipalName}';
let TimeFrame = {TimeFrame};
SigninLogs
// Filter only successful sign-ins
| where TimeGenerated > ago(TimeFrame)
| where UserPrincipalName =~ Upn
| where ResultType == 0
| where AuthenticationProtocol == 'deviceCode'
// optional filter on unmanaged devices
// | where isempty(DeviceDetail.deviceId)
| extend operatingSystem = tostring(DeviceDetail.operatingSystem)
// Optionally filter only on sign-ins with a risklevel associated with the sign-in
//| where RiskLevelDuringSignIn != 'none'
| project-reorder TimeGenerated, UserPrincipalName, AuthenticationProtocol, ResultType, RiskLevelDuringSignIn, AppDisplayName, AppId, Location, IPAddress

let Upn = '{UserPrincipalName}';
let TimeFrame = {TimeFrame};
let WhitelistedObjects = dynamic(['obj1', 'obj2']);
let UniqueRequestThreshold = 500; // Depends on Entra ID tentant size. You can use the function 0.5 * TotalAzure Resources to get this number. KQL: arg('').Resources | count
let ResourceThreshold = 4;
let ReconResources = dynamic(['organization','groups','devices','applications','users','rolemanagement','serviceprincipals']);
let ObjectId = SigninLogs
| where TimeGenerated > ago(TimeFrame)
| where UserPrincipalName =~ Upn
| distinct UserId;
GraphAPIAuditEvents
| where AccountObjectId in~ (ObjectId)
| where TimeGenerated > ago(TimeFrame)
| where RequestMethod == 'GET'
| where ResponseStatusCode == 200
| extend ParsedUri = tostring(parse_url(RequestUri).Path)
| extend GraphAPIPath = tolower(replace_string(ParsedUri, '//', '/'))
| extend GraphAPIResource = tostring(split(GraphAPIPath, '/')[2])
| where GraphAPIResource in (ReconResources)
// Filter whitelist
| where not(AccountObjectId in (WhitelistedObjects))
| summarize UniqueRequests = dcount(ClientRequestId), Requests = make_set(RequestUri, 1000), Paths = make_set(GraphAPIPath), Resources = make_set(GraphAPIResource), UniqueResourceCount = dcount(GraphAPIResource) by AccountObjectId, bin(TimeGenerated, 1h)
| where UniqueRequests >= UniqueRequestThreshold and UniqueResourceCount >= ResourceThreshold

let Upn = '{UserPrincipalName}';
let TimeFrame = {TimeFrame};
let DefaultInboxFolders = pack_array('Inbox', 'Drafts', 'Sent Items', 'Archive', 'rss', 'Inbox', 'Deleted Items', 'Junk Email');
let BinSize = 30m;
let MaxSuccess = 10;
let MailBoxSyncOperations = CloudAppEvents
// List all MailItemsAccessed that are created because of a sync audit activity.
// The audit volume for sync operations is huge. So, instead of generating an audit record for each mail item that's synched, we generate an audit event for the mail folder containing items that were synched and assume that all mail items in the synched folder have been compromised.
// Info: https://learn.microsoft.com/en-us/purview/audit-log-investigate-accounts?view=o365-worldwide#auditing-sync-access
| where ActionType == 'MailItemsAccessed'
| extend MailAccessType = toint(RawEventData.RecordType), IsThrottled = tostring(parse_json(RawEventData.OperationCount))
| where MailAccessType == 2
// Parse synchronised folders. All FolderNames should be considered compromised.
| extend ParentFolder = parse_json(RawEventData.Item).ParentFolder
| extend SyncedFolder = tostring(ParentFolder.Name), Path = tostring(ParentFolder.Path), MailboxGuid = tostring(parse_json(RawEventData.MailboxGuid)), UserId = tolower(parse_json(RawEventData.UserId))
| where UserId =~ Upn
| summarize TotalFolers = dcount(SyncedFolder), Folders = make_set(SyncedFolder) by bin(TimeGenerated, BinSize), UserId, IPAddress, MailboxGuid;
let LargeSyncOperations = MailBoxSyncOperations
// Filter & enrich results
| where TotalFolers >= array_length(DefaultInboxFolders)
| extend GeoIPInfo = geo_info_from_ip_address(IPAddress)
| extend country = tostring(parse_json(GeoIPInfo).country);
LargeSyncOperations
| join kind=inner (AADSignInEventsBeta | where TimeGenerated > startofday(ago(TimeFrame)) and LogonType has 'interactiveUser' | project ErrorCode, AccountUpn = tolower(AccountUpn), IPAddress | summarize TotalSuccess = countif(ErrorCode == 0), TotalFailed = countif(ErrorCode != 0) by AccountUpn, IPAddress) on $left.IPAddress == $right.IPAddress, $left.UserId == $right.AccountUpn
// Filter only on IPs with low successrate 
| where TotalSuccess <= MaxSuccess
